import{_ as s,c as i,o as t,ae as n}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"⚙️ Gestion de la configuration de notre site","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/site_config.md","filePath":"drupal-project/installation/site_config.md"}'),a={name:"drupal-project/installation/site_config.md"};function o(l,e,r,p,d,c){return t(),i("div",null,e[0]||(e[0]=[n(`<h1 id="⚙️-gestion-de-la-configuration-de-notre-site" tabindex="-1">⚙️ Gestion de la configuration de notre site <a class="header-anchor" href="#⚙️-gestion-de-la-configuration-de-notre-site" aria-label="Permalink to &quot;⚙️ Gestion de la configuration de notre site&quot;">​</a></h1><h2 id="configuration-contenu" tabindex="-1">Configuration !== contenu <a class="header-anchor" href="#configuration-contenu" aria-label="Permalink to &quot;Configuration !== contenu&quot;">​</a></h2><p><strong>Drupal</strong> est un gestionnaire de contenu qui permet de concevoir et gérer un site internet sans avoir besoin de connaître le développement web.</p><p>Mais pour l&#39;utiliser de manière efficace, il est très important de bien comprendre la distinction entre la <strong>configuration</strong> et le <strong>contenu</strong>.</p><p>La <strong>configuration</strong> représente tous les changements que l&#39;on fait dans l&#39;administration de notre site. Ces changements se font dans l&#39;espace administrateur. Elle correspond par exemple à :</p><ul><li>Créer un vocabulaire de taxonomie.</li><li>Ajouter des champs à un type de contenu.</li><li>Mettre le site en mode maintenance.</li><li>Etc..</li></ul><p>Le <strong>contenu</strong> de son côté représente tout le contenu que l&#39;on ajoute au site. Elle correspond par exemple à :</p><ul><li>Ajouter une liste de termes à une taxonomie.</li><li>Créer une page sur notre site en remplissant les champs d&#39;un type de contenu.</li><li>Ajouter des liens à notre menu principal.</li><li>Etc..</li></ul><p>Je sais que pour le moment tout ça peut paraître flou. Ne vous inquiétez pas, nous aurons l&#39;occasion de revenir en long, en large et en travers sur cette distinction.</p><p>L&#39;important était de vous présenter cette distinction. Car dans ce chapitre, nous allons nous intéresser à la <strong>configuration</strong>.</p><div class="warning custom-block"><p class="custom-block-title">⚠️ Attention</p><p>Dans le reste de ce chapitre, lorsque je fais mention à la <strong>configuration</strong>, je parle bien des modifications que l&#39;on fait dans l&#39;espace administrateur du site.</p></div><p>Dans <strong>Drupal</strong>, lorsque nous effectuons des changements dans l&#39;administration, ces informations sont enregistrées en base de données.</p><p>Mais <strong>Drupal</strong> offre également une fonctionnalité très pratique : l&#39;export de la configuration dans des fichiers <em>.yml</em>. Ces fichiers représentent l&#39;ensemble des paramètres et réglages du site. Ce qui permet de :</p><ul><li><strong>Versionner</strong> la configuration avec <strong>Git</strong>, comme on le fait avec le code.</li><li><strong>Travailler en équipe</strong> : chaque développeur peut importer ou exporter la configuration sur sa propre instance et rester synchronisé avec les autres.</li><li><strong>Faciliter les déploiements</strong> : la configuration d&#39;un environnement de développement peut être transférée vers un autre environnement de recette ou de production.</li></ul><p>En résumé, la gestion de la configuration via des fichiers exportables rend le développement de <strong>Drupal</strong> plus fluide, reproductible et collaboratif. C&#39;est un des éléments clef des bonnes pratiques pour tous les projets, même de petites tailles.</p><div class="info custom-block"><p class="custom-block-title">❓Mais pourquoi je vous parle de tout ça alors qu&#39;on n&#39;a même pas encore été dans l&#39;administration du site ?</p><p>Parce que nous avons des changements à faire dans les dossiers de notre projet et le fichier <em>settings.php</em> pour gérer efficacement ces fichiers de configuration.</p></div><h2 id="gerer-les-fichiers-yml-de-configuration" tabindex="-1">Gérer les fichiers .yml de configuration <a class="header-anchor" href="#gerer-les-fichiers-yml-de-configuration" aria-label="Permalink to &quot;Gérer les fichiers .yml de configuration&quot;">​</a></h2><p>Lors de l&#39;installation du projet, <strong>DDEV</strong> a défini dans quel dossier les fichiers de configurations seront enregistrés :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># web/sites/default/settings.ddev.php</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Set $settings[&#39;config_sync_directory&#39;] if not set in settings.php.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">empty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($settings[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;config_sync_directory&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  $settings[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;config_sync_directory&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sites/default/files/sync&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Par défaut, les configurations sont enregistrées dans le dossier <em>web/sites/default/files/sync</em>. Ce qui n&#39;est pas une bonne pratique car le dossier <em>/files</em> est ignoré par <strong>Git</strong>. (Nous l&#39;avons ajouté à notre <em>.gitignore</em>).</p><p>Je trouve plus logique et pratique que les fichiers de configuration soient désolidarisés du dossier <em>web</em>.</p><p>A la racine du projet, créez les dossiers <em>config/default</em> :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/default</span></span></code></pre></div><p>Nous allons également créer un fichier spécifique à la configuration dans le dossier <em>web/sites/default/settings</em> :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">touch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web/sites/default/settings/config.php</span></span></code></pre></div><p>Nous pouvons ajouter le code suivant :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">php</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Define the config sync folder</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$settings[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;config_sync_directory&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;../config/default&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ Par défaut, les fichiers settings sont dans le dossier <em>web</em>.</p><p>Il faut donc revenir en arrière dans l&#39;arborescence pour trouver notre dossier <em>config</em>.</p></div><div class="tip custom-block"><p class="custom-block-title">Pas besoin de faire plus !</p><p>Rappelez-vous l&#39;ordre de chargement des settings :</p><p>les fichiers du dossier <em>settings/</em> -&gt; <em>settings.ddev.php</em> -&gt; <em>settings.local.php</em></p><p>Même si le fichier <em>settings.ddev.php</em> se charge après notre fichier <em>settings/config.php</em>, il n&#39;y a pas de risque de surcharge, car si vous analysez le code dans <em>settings.ddev.php</em>, vous remarquerez que la valeur n&#39;est surchargée que si elle est vide.</p><p>C&#39;est donc bien la valeur dans <em>settings/config.php</em> qui sera utilisée.</p></div><p>Nous pouvons maintenant supprimer le dossier de configuration d&#39;origine.</p><h2 id="exporter-la-configuration-actuelle" tabindex="-1">Exporter la configuration actuelle <a class="header-anchor" href="#exporter-la-configuration-actuelle" aria-label="Permalink to &quot;Exporter la configuration actuelle&quot;">​</a></h2><p>Depuis le début de ce chapitre, nous évoquons la possibilité d&#39;exporter la configuration de notre site.</p><p>Mais on fait ça comment ?</p><p>Avec <strong>Drush</strong> tout simplement !</p><p>Nous allons d&#39;abord utiliser la commande <strong>Drush</strong> qui permet de supprimer le cache pour que nos dernières modifications soient prises en compte.</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cr</span></span></code></pre></div><p>Puis nous allons utiliser la commande qui permet d&#39;exporter la configuration :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drush</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cex</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">💡Que signifie cette commande ?</p><p><code>drush cex</code> est l&#39;alias de la commande <code>drush config:export</code>.</p></div><p>Le terminal devrait afficher le message suivant :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[success] Configuration successfully exported to ../config/default.</span></span></code></pre></div><p>Et si vous regardez dans le dossier <em>config/default</em>, vous devriez trouver un grand nombre de fichiers <em>.yml</em>.</p><p>Nous n&#39;allons pas les analyser un par un. Mais parmi eux, il est intéressant de citer <em>config/default/system.site.yml</em> qui contient les informations de notre site. On y retrouve d&#39;ailleurs le nom de notre site ainsi que l&#39;adresse mail que nous avons indiqué lors de l&#39;installation dans l&#39;interface d&#39;installation web.</p><p>Un autre fichier intéressant est <em>config/default/core.extension.yml</em>. Il référence tous les modules initialisés. Nous pouvons voir <code>dotenv</code> dans la liste.</p><div class="info custom-block"><p class="custom-block-title">Et ensuite ?</p><p><strong>Drupal</strong> est installé, la configuration principale est en place, nous allons bientôt manipuler <strong>Drupal</strong>. Mais il reste tout de même quelques étapes pour faciliter le travail et surtout améliorer la maintenabilité de notre projet.</p><p>Commençons par ajouter <strong>PHPMyAdmin</strong> pour <a href="/drupal-project/installation/phpmyadmin.html">gérer notre base de données</a>.</p></div>`,45)]))}const g=s(a,[["render",o]]);export{h as __pageData,g as default};
